code.Java:
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String s = br.readLine();
            if (s == null) break;
            int choice = Integer.parseInt(s.trim());
            if (choice == 1) sb.append("Option 1 selected");
            else if (choice == 2) sb.append("Option 2 selected");
            else if (choice == 3) sb.append("Option 3 selected");
            else sb.append("Invalid choice");
            if (i != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        if idx >= len(data):
            break
        choice = int(data[idx])
        idx += 1
        if choice == 1:
            out.append("Option 1 selected")
        elif choice == 2:
            out.append("Option 2 selected")
        elif choice == 3:
            out.append("Option 3 selected")
        else:
            out.append("Invalid choice")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

